31: // Returns a Set that includes every Vertex yielded by walking down from the
32: // provided starting Vertex v.
33: func (g *AcyclicGraph) Ancestors(vs ...Vertex) (Set, error) {
34: 	s := make(Set)
35: 	memoFunc := func(v Vertex, d int) error {
36: 		s.Add(v)
37: 		return nil
38: 	}
39: 
40: 	start := make(Set)
41: 	for _, v := range vs {
42: 		for _, dep := range g.downEdgesNoCopy(v) {
43: 			start.Add(dep)
44: 		}
45: 	}
46: 
47: 	if err := g.DepthFirstWalk(start, memoFunc); err != nil {
48: 		return nil, err
49: 	}
50: 
51: 	return s, nil
52: }
53: 
54: // Returns a Set that includes every Vertex yielded by walking up from the
55: // provided starting Vertex v.
56: func (g *AcyclicGraph) Descendents(vs ...Vertex) (Set, error) {
57: 	s := make(Set)
58: 	memoFunc := func(v Vertex, d int) error {
59: 		s.Add(v)
60: 		return nil
61: 	}
62: 
63: 	start := make(Set)
64: 	for _, v := range vs {
65: 		for _, dep := range g.upEdgesNoCopy(v) {
66: 			start.Add(dep)
67: 		}
68: 	}
69: 
70: 	if err := g.ReverseDepthFirstWalk(start, memoFunc); err != nil {
71: 		return nil, err
72: 	}
73: 
74: 	return s, nil
75: }
