77: // Root returns the root of the DAG, or an error.
78: //
79: // Complexity: O(V)
80: func (g *AcyclicGraph) Root() (Vertex, error) {
81: 	roots := make([]Vertex, 0, 1)
82: 	for _, v := range g.Vertices() {
83: 		if g.upEdgesNoCopy(v).Len() == 0 {
84: 			roots = append(roots, v)
85: 		}
86: 	}
87: 
88: 	if len(roots) > 1 {
89: 		// TODO(mitchellh): make this error message a lot better
90: 		return nil, fmt.Errorf("multiple roots: %#v", roots)
91: 	}
92: 
93: 	if len(roots) == 0 {
94: 		return nil, fmt.Errorf("no roots found")
95: 	}
96: 
97: 	return roots[0], nil
98: }
