100: // TransitiveReduction performs the transitive reduction of graph g in place.
101: // The transitive reduction of a graph is a graph with as few edges as
102: // possible with the same reachability as the original graph. This means
103: // that if there are three nodes A => B => C, and A connects to both
104: // B and C, and B connects to C, then the transitive reduction is the
105: // same graph with only a single edge between A and B, and a single edge
106: // between B and C.
107: //
108: // The graph must be free of cycles for this operation to behave properly.
109: //
110: // Complexity: O(V(V+E)), or asymptotically O(VE)
111: func (g *AcyclicGraph) TransitiveReduction() {
112: 	// For each vertex u in graph g, do a DFS starting from each vertex
113: 	// v such that the edge (u,v) exists (v is a direct descendant of u).
114: 	//
115: 	// For each v-prime reachable from v, remove the edge (u, v-prime).
116: 	for _, u := range g.Vertices() {
117: 		uTargets := g.downEdgesNoCopy(u)
118: 
119: 		g.DepthFirstWalk(g.downEdgesNoCopy(u), func(v Vertex, d int) error {
120: 			shared := uTargets.Intersection(g.downEdgesNoCopy(v))
121: 			for _, vPrime := range shared {
122: 				g.RemoveEdge(BasicEdge(u, vPrime))
123: 			}
124: 
125: 			return nil
126: 		})
127: 	}
128: }
