130: // Validate validates the DAG. A DAG is valid if it has a single root
131: // with no cycles.
132: func (g *AcyclicGraph) Validate() error {
133: 	if _, err := g.Root(); err != nil {
134: 		return err
135: 	}
136: 
137: 	// Look for cycles of more than 1 component
138: 	var err error
139: 	cycles := g.Cycles()
140: 	if len(cycles) > 0 {
141: 		for _, cycle := range cycles {
142: 			cycleStr := make([]string, len(cycle))
143: 			for j, vertex := range cycle {
144: 				cycleStr[j] = VertexName(vertex)
145: 			}
146: 
147: 			err = errors.Join(err, fmt.Errorf(
148: 				"Cycle: %s", strings.Join(cycleStr, ", ")))
149: 		}
150: 	}
